import{_ as a,o as t,c as i,a2 as n}from"./chunks/framework.CHeM0PsO.js";const u=JSON.parse('{"title":"Real-device PWA testing","description":"","frontmatter":{"docSection":"contributors","docType":"guide","audiences":["contributor"]},"headers":[],"relativePath":"pwa-real-device-testing.md","filePath":"pwa-real-device-testing.md"}'),s={name:"pwa-real-device-testing.md"};function o(l,e,r,h,c,p){return t(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="real-device-pwa-testing" tabindex="-1">Real-device PWA testing <a class="header-anchor" href="#real-device-pwa-testing" aria-label="Permalink to &quot;Real-device PWA testing&quot;">​</a></h1><p>Sovereign is an installable PWA, so browser mobile emulation is not enough for PWA-sensitive work. Chrome or Playwright mobile view can catch layout issues, but it does not fully match an installed PWA on iPhone or Android.</p><p>iOS Safari and Home Screen PWAs differ in viewport sizing, safe-area handling, service-worker behavior, cache state, standalone navigation, and notification support. Android Chrome has its own install, cache, and notification behavior. When a change touches the shell, auth/login flow, service worker, manifest, offline behavior, push notifications, mobile layout, safe-area handling, or install experience, test on a real device before deploy.</p><h2 id="what-an-ai-agent-can-do" tabindex="-1">What an AI agent can do <a class="header-anchor" href="#what-an-ai-agent-can-do" aria-label="Permalink to &quot;What an AI agent can do&quot;">​</a></h2><p>An AI agent can prepare and verify most of the test setup:</p><ul><li>run the production build and start command;</li><li>expose the local app through a phone-reachable URL;</li><li>verify browser-facing runtime/auth URLs do not point at <code>localhost</code>;</li><li>provide the human with a concise device checklist;</li><li>record the human&#39;s iPhone or Android observations in the PR notes.</li></ul><p>An AI agent cannot fully validate installed-PWA behavior unless it has access to a physical device, emulator with the relevant PWA support, or a real-device cloud. If no device automation is available, the final installed-PWA check is a human handoff.</p><h2 id="preferred-path-https-tunnel" tabindex="-1">Preferred path: HTTPS tunnel <a class="header-anchor" href="#preferred-path-https-tunnel" aria-label="Permalink to &quot;Preferred path: HTTPS tunnel&quot;">​</a></h2><p>Use an HTTPS tunnel for realistic PWA checks. HTTPS is required for service workers, installability, WebAuthn origin behavior, push notifications, and many browser APIs outside <code>localhost</code>.</p><p>Build and start the app:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span></code></pre></div><p>Expose the runtime with Cloudflare Tunnel:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cloudflared</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tunnel</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:3000</span></span></code></pre></div><p>Or expose it with ngrok:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ngrok</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3000</span></span></code></pre></div><p>Open the generated HTTPS URL on the phone, install the PWA from the browser, then test the installed app from the Home Screen or app launcher.</p><h2 id="fast-path-local-network-url" tabindex="-1">Fast path: local network URL <a class="header-anchor" href="#fast-path-local-network-url" aria-label="Permalink to &quot;Fast path: local network URL&quot;">​</a></h2><p>A local network URL is useful for quick mobile layout, touch, keyboard, and safe-area checks. It is not a complete PWA test.</p><p>Find the development machine&#39;s LAN IP:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ipconfig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> getifaddr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> en0</span></span></code></pre></div><p>Then open the app from the phone:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://&lt;lan-ip&gt;:3000</span></span></code></pre></div><p>Use this path for quick checks only. Plain <code>http://192.168.x.x</code> usually does not provide a secure context, so service workers, push notifications, installability, and auth-origin behavior may not match production.</p><h2 id="local-https-on-lan" tabindex="-1">Local HTTPS on LAN <a class="header-anchor" href="#local-https-on-lan" aria-label="Permalink to &quot;Local HTTPS on LAN&quot;">​</a></h2><p>Local HTTPS on the LAN avoids a third-party tunnel, but it takes more setup:</p><ul><li>generate a trusted local certificate;</li><li>serve the runtime over HTTPS;</li><li>make the phone trust the certificate;</li><li>configure browser-facing runtime and auth URLs to the HTTPS LAN origin.</li></ul><p>Use this when tunnel services are unavailable or when testing must stay entirely on the local network.</p><h2 id="auth-and-runtime-url-checks" tabindex="-1">Auth and runtime URL checks <a class="header-anchor" href="#auth-and-runtime-url-checks" aria-label="Permalink to &quot;Auth and runtime URL checks&quot;">​</a></h2><p>For shell/install/cache checks, a single runtime tunnel may be enough. For login/session testing, the auth server must also be reachable from the phone. Do not leave browser-facing URLs pointed at <code>localhost</code>, because that resolves on the phone, not on the development machine.</p><p>Check the relevant environment variables before handing the test to a device:</p><ul><li><code>NEXT_PUBLIC_RUNTIME_URL</code></li><li><code>SOVEREIGN_AUTH_PUBLIC_URL</code></li><li><code>SOVEREIGN_AUTH_URL</code></li><li><code>AUTH_BASE_URL</code></li><li><code>AUTH_WEBAUTHN_ORIGIN</code></li></ul><p>These should use phone-reachable HTTPS origins for full installed-PWA testing.</p><h2 id="device-checklist" tabindex="-1">Device checklist <a class="header-anchor" href="#device-checklist" aria-label="Permalink to &quot;Device checklist&quot;">​</a></h2><p>Run this checklist on each real device used for validation:</p><ul><li>Install from Safari on iOS or Chrome on Android.</li><li>Launch from the Home Screen or app launcher, not only the browser tab.</li><li>Confirm the app opens in standalone PWA mode.</li><li>Confirm login stays inside the PWA instead of opening a separate browser tab.</li><li>Check safe areas: top header, bottom navigation, overlays, and keyboard-open states.</li><li>Navigate between Launcher, Account, Console/admin-only surfaces, and a normal plugin.</li><li>Background and resume the PWA.</li><li>Toggle offline/online or airplane mode and verify the offline banner and reload behavior.</li><li>For cache or service-worker changes, verify both a fresh install and an upgrade from a previously installed version.</li><li>For push-notification changes, verify permission request, subscription, delivery, tap behavior, and denied-permission behavior.</li></ul><p>Record the device model, OS version, browser, app URL, and any platform-specific differences.</p><h2 id="resetting-iphone-pwa-state" tabindex="-1">Resetting iPhone PWA state <a class="header-anchor" href="#resetting-iphone-pwa-state" aria-label="Permalink to &quot;Resetting iPhone PWA state&quot;">​</a></h2><p>When testing cache or service-worker changes on iPhone, reset app state between runs:</p><ol><li>Delete the Home Screen PWA.</li><li>Open <strong>Settings -&gt; Safari -&gt; Advanced -&gt; Website Data</strong>.</li><li>Delete the tested domain&#39;s website data.</li><li>Reopen the URL in Safari and reinstall the PWA.</li></ol><p>This gives a cleaner install/cache state than deleting the Home Screen icon alone.</p>`,40)])])}const g=a(s,[["render",o]]);export{u as __pageData,g as default};
